=<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<meta http-equiv="Content-Type" content="text/html; charset=utf-8">
<title>Economic Insight</title>
<style>
    /* Email-safe styles */
    body {
        font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Arial, Helvetica, sans-serif;
        background: #f5f7fa;
        margin: 0;
        padding: 0;
        color: #1a2332;
        -webkit-text-size-adjust: 100%;
    }
    .container {
        max-width: 620px;
        margin: 0 auto;
        background: #ffffff;
        border-radius: 8px;
        overflow: hidden;
    }
    .header {
        background: #0f1a2e;
        padding: 20px 25px;
    }
    .header h1 {
        margin: 0;
        color: #ffffff;
        font-weight: 400;
        font-size: 20px;
    }
    .header h1 span { font-weight: 700; color: #e8b82a; }
    .header .date {
        color: #8899aa;
        font-size: 12px;
        margin-top: 2px;
    }
    .content { padding: 20px 25px; }
    .question-box {
        background: #f0f4fe;
        border-radius: 6px;
        padding: 12px 16px;
        margin-bottom: 18px;
        border-left: 3px solid #1a5c9e;
    }
    .question-box .label {
        font-size: 10px;
        text-transform: uppercase;
        letter-spacing: 0.5px;
        color: #1a5c9e;
        font-weight: 700;
        margin-bottom: 3px;
    }
    .question-box .text {
        font-size: 15px;
        font-weight: 500;
        color: #0f1a2e;
        margin: 0;
        line-height: 1.4;
    }
    .answer-box .label {
        font-size: 10px;
        text-transform: uppercase;
        letter-spacing: 0.5px;
        color: #6b7a8a;
        font-weight: 700;
        margin-bottom: 5px;
        display: block;
    }
    .answer-box .content {
        background: #fafbfc;
        border-radius: 6px;
        padding: 14px 16px;
        border: 1px solid #eaeef2;
        font-size: 14px;
        line-height: 1.6;
        color: #1e2a3a;
        margin: 0 0 18px 0;
    }
    .meta-table {
        width: 100%;
        border-collapse: collapse;
        background: #f8f9fb;
        border-radius: 6px;
        border: 1px solid #eaeef2;
        margin: 14px 0 0 0;
    }
    .meta-table td {
        padding: 8px 12px;
        vertical-align: top;
        width: 33.33%;
    }
    .meta-label {
        font-size: 9px;
        text-transform: uppercase;
        letter-spacing: 0.4px;
        color: #8a9aa8;
        font-weight: 700;
        display: block;
    }
    .meta-value {
        font-size: 13px;
        color: #1e2a3a;
        font-weight: 500;
        display: block;
        margin-top: 1px;
    }
    .footer {
        background: #f8f9fb;
        padding: 14px 25px;
        border-top: 1px solid #eaeef2;
        font-size: 11px;
        color: #7a8a9a;
        line-height: 1.5;
    }
    .footer .disclaimer {
        color: #c0392b;
        font-weight: 600;
    }
    .footer a {
        color: #1a5c9e;
        text-decoration: underline;
    }
    /* Mobile friendly */
    @media only screen and (max-width: 480px) {
        .header { padding: 16px 18px; }
        .header h1 { font-size: 18px; }
        .content { padding: 16px 18px; }
        .meta-table td { display: block; width: 100%; padding: 4px 12px; }
        .footer { padding: 12px 18px; }
    }
</style>
</head>
<body>

<table width="100%" cellpadding="0" cellspacing="0" border="0" bgcolor="#f5f7fa">
    <tr>
        <td align="center" style="padding: 20px 0;">
            <div class="container">

                <!-- HEADER -->
                <div class="header">
                    <h1>📊 Economic <span>Insight</span></h1>
                    <div class="date">{{ $now.format('dd MMM yyyy') }} &bull; {{ $now.format('HH:mm') }}</div>
                </div>

                <!-- CONTENT -->
                <div class="content">

                    <!-- Question (pulled directly from the original Webhook trigger node, not the API response) -->
                    <div class="question-box">
                        <div class="label">📌 Your Inquiry</div>
                        <p class="text">{{ $('Webhook').item.json.body.question || $('Webhook').item.json.question || $json.question || 'No question provided' }}</p>
                    </div>

                    <!-- Answer -->
                    <div class="answer-box">
                        <span class="label">💡 Analysis</span>
                        <div class="content">
                            {{ $json.response || 'No analysis available' }}
                        </div>
                    </div>

                    <!-- Meta -->
                    <table class="meta-table" cellpadding="0" cellspacing="0" border="0">
                        <tr>
                            <td><span class="meta-label">🔄 Processing</span><span class="meta-value">{{ $json.iterations || 'N/A' }}</span></td>
                            <td><span class="meta-label">📊 Source</span><span class="meta-value">Economic Advisor AI</span></td>
                            <td><span class="meta-label">🔒 Confidence</span><span class="meta-value">{{ $json.confidence || 'High' }}</span></td>
                        </tr>
                    </table>

                </div>

                <!-- FOOTER -->
                <div class="footer">
                    <span class="disclaimer">⚠️ Not financial advice</span> &bull; For educational purposes only<br>
                    Generated by Economic Advisor AI &bull; <a href="{{ $json.unsubscribe_link || '#' }}">Unsubscribe</a>
                </div>

            </div>
        </td>
    </tr>
</table>

</body>
</html>
